Sample code (using node 8.13.0, driver 3.2.7 and mongo 4.10.0):
{code}'use strict';

const { MongoClient, Timestamp } = require('mongodb');

function getCollection(database, collectionName) {
    return new Promise((resolve, reject) => {
        database.collection(collectionName, { strict: true }, (err, collection) => {
            if(err) {
                reject(err);
            } else {
                resolve(collection);
            }
        });
    });
}

(async () => {
    const mongoOptions = {
        socketTimeoutMS: 5000,
        useNewUrlParser: true
    };

    const client = await MongoClient.connect('mongodb://mongo1,mongo2,mongo3/myTestDatabase?replicaSet=rs0', mongoOptions);
    const database = client.db('myTestDatabase');
    const collection = await getCollection(database, 'myTestCollection');

    const changeStreamCursor = collection.watch(
        [{ $match: { operationType: { $in: ['insert', 'update', 'replace', 'delete'] } } }],
        {
            fullDocument: 'updateLookup',
            startAtOperationTime: new Timestamp(0, (Date.now() / 1000) | 0),
        }
    );

    changeStreamCursor.on('end', () => { console.error('End o\' cursor'); });
    changeStreamCursor.on('close', () => { console.warn('Cursor closed!'); });
    changeStreamCursor.on('error', (error) => { console.error('Error', error); });
    changeStreamCursor.on('change', (event) => { console.log('Event: ', event); });
})();
{code}

Currently the {{AutoEncrypter}} is stored in the topology {{options}}, which is cloned to individual {{Server}} instances. This makes access somewhat cumbersome in the wire protocol methods, leading to checks like:
{code:java}
server && server.s && server.s.options && server.s.options.autoEncrypter;
{code}

We can follow patterns we use for e.g. {{Collection.readConcern}} to make this more readable.

The {{readConcern}} tests reuse quite a bit of boilerplate code. As [~matt.broadstone] suggested, we should simplify these tests to use a format like 

{code:java}
[
  {
    description: 'should set majority readConcern option for aggregate command',
    operation: coll => coll.aggregate([{ $match: {} }], { readConcern: { level: 'majority' } })
].forEach(testCase => {
  it(testCase.description, () => { ... });
});
{code}

and provide a helper for command monitoring, like

{code}
it('should do something with command monitoring', commandMonitoringTest(done => {
  ... other setup ...
  return collection
    .aggregate([{ $match: {} }], { readConcern: { level: 'majority' } })
    .toArray(function(err) {
      const aggEvents = this.started.filter(evt => evt.name === 'aggregate');
      const toCheck = aggEvents[0];
      ... the rest ...
    });
}));
{code}

The command monitoring helper would be responsible for instrumenting before the test, maintaining a list of started/failed/succeeded events for introspection, and uninstrumenting after the test.

{{collection_tests}} has a lot of duplication that we can reduce. Most of the tests follow this pattern:

{code:java}
var self = this;
var client = self.configuration.newClient();
client.connect(function(err, client) {
  var db = client.db(self.configuration.db);

  db.createCollection('test_collection_methods', function(err, collection) {
     test.equal('test_collection_methods', collection.collectionName);

     // some operation
  });
});
{code}

We can move this common behavior into {{beforeEach}} to reduce duplication across tests that follow this pattern. While doing that, we can also replace {{var}} with {{const}} or {{let}} as needed, eliminate the use of {{self}}, and switch to arrow functions.
